import AnimatedCursor from 'react-animated-cursor';
import { isMobile } from 'react-device-detect';

const VoidAnimatedCursor = () =>
  isMobile ? null : (
    <AnimatedCursor
      color="139,233,253"
      innerSize={10}
      outerSize={40}
      innerScale={1}
      outerScale={2}
      outerAlpha={1}
      innerStyle={{
        backgroundColor: 'rgb(255, 255, 255)',
        mixBlendMode: 'exclusion',
        zIndex: '999',
      }}
      outerStyle={{
        mixBlendMode: 'exclusion',
      }}
    />
  );

export default VoidAnimatedCursor;
